//
// C helper wrappers for kernel functions that are macros or static inlines.
// These create real symbols that Rust can link against.
//
// The Rust FFI bindings for these functions are auto-generated by bnd-winmd
// from helpers.h.

#include <linux/kconfig.h>
#include <linux/mm.h>
#include <linux/fs.h>
#include <linux/pagemap.h>
#include <linux/highmem.h>
#include <linux/slab.h>

#include "helpers.h"

// Folio helpers

void rust_helper_folio_get(struct folio *folio)
{
	folio_get(folio);
}

void rust_helper_folio_put(struct folio *folio)
{
	folio_put(folio);
}

loff_t rust_helper_folio_pos(struct folio *folio)
{
	return folio_pos(folio);
}

size_t rust_helper_folio_size(struct folio *folio)
{
	return folio_size(folio);
}

void rust_helper_folio_mark_uptodate(struct folio *folio)
{
	folio_mark_uptodate(folio);
}

void rust_helper_folio_end_read(struct folio *folio, bool success)
{
	folio_end_read(folio, success);
}

void rust_helper_flush_dcache_folio(struct folio *folio)
{
	flush_dcache_folio(folio);
}

void *rust_helper_kmap_local_folio(struct folio *folio, size_t offset)
{
	return kmap_local_folio(folio, offset);
}

void rust_helper_kunmap_local(const void *vaddr)
{
	kunmap_local(vaddr);
}

// Inode helpers

void *rust_helper_alloc_inode_sb(struct super_block *sb,
				 struct kmem_cache *cache, gfp_t gfp)
{
	return alloc_inode_sb(sb, cache, gfp);
}

void rust_helper_i_uid_write(struct inode *inode, uid_t uid)
{
	i_uid_write(inode, uid);
}

void rust_helper_i_gid_write(struct inode *inode, gid_t gid)
{
	i_gid_write(inode, gid);
}

void rust_helper_mapping_set_large_folios(struct address_space *mapping)
{
	mapping_set_large_folios(mapping);
}

void rust_helper_inode_set_flags(struct inode *inode,
				 unsigned int flags, unsigned int mask)
{
	inode_set_flags(inode, flags, mask);
}

void rust_helper_set_nlink(struct inode *inode, unsigned int nlink)
{
	set_nlink(inode, nlink);
}

// Directory emit helper

bool rust_helper_dir_emit(struct dir_context *ctx, const char *name,
			  int namelen, u64 ino, unsigned char type)
{
	return dir_emit(ctx, name, namelen, ino, type);
}

// Device number helper

unsigned int rust_helper_MKDEV(unsigned int major, unsigned int minor)
{
	return MKDEV(major, minor);
}

// kmem_cache helper

struct kmem_cache *rust_helper_kmem_cache_create(const char *name,
						  unsigned int size,
						  unsigned int align,
						  unsigned long flags,
						  void (*ctor)(void *))
{
	return kmem_cache_create(name, size, align, flags, ctor);
}

// Dentry name helpers

const unsigned char *rust_helper_dentry_name(const struct dentry *dentry)
{
	return dentry->d_name.name;
}

unsigned int rust_helper_dentry_name_len(const struct dentry *dentry)
{
	return dentry->d_name.len;
}

// ERR_PTR / IS_ERR / PTR_ERR helpers

void *rust_helper_ERR_PTR(long error)
{
	return ERR_PTR(error);
}

long rust_helper_PTR_ERR(const void *ptr)
{
	return PTR_ERR(ptr);
}

bool rust_helper_IS_ERR(const void *ptr)
{
	return IS_ERR(ptr);
}

// file->f_inode accessor

struct inode *rust_helper_file_inode(const struct file *f)
{
	return f->f_inode;
}

// inode ops setters (i_fop is in an anonymous union, not visible to bnd)

void rust_helper_inode_set_fop(struct inode *inode,
			       const struct file_operations *fop)
{
	inode->i_fop = fop;
}

void rust_helper_inode_set_aops(struct inode *inode,
				const struct address_space_operations *aops)
{
	inode->i_data.a_ops = aops;
}

// generic_file_read_iter wrapper

ssize_t rust_helper_generic_file_read_iter(struct kiocb *iocb,
					   struct iov_iter *to)
{
	return generic_file_read_iter(iocb, to);
}

// is_bad_inode wrapper

bool rust_helper_is_bad_inode(struct inode *inode)
{
	return is_bad_inode(inode);
}

